// HCPA - Residência Médica 2023 (Acesso Direto e Prova de Autoavaliação)
export const HCPA_2023_QUESTIONS: any[] = [
  { id: "hcpa_2023_001", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "O nascimento de um neonato com 36 semanas de idade gestacional ocorreu via parto vaginal, sem necessidade de fórceps. A evolução do parto transcorreu dentro da normalidade. O recém-nascido foi posicionado sobre o ventre materno, tendo apresentado cianose, choro forte e tônus adequado. Diante do quadro, deve-se realizar o clampeamento do cordão umbilical", options: ["imediatamente, por se tratar de um prematuro.", "imediatamente, por se tratar de um recém-nascido cianótico.", "após 30 segundos de vida, por se tratar de um prematuro.", "após 60 segundos de vida, por ter o prematuro nascido vigoroso."], correctIndex: 3 },
  { id: "hcpa_2023_002", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Gestante com diabetes gestacional e pré-eclâmpsia, em uso de insulina e metildopa, deu à luz recém-nascido pré-termo (36 semanas, 2.580 g) por cesárea. Em tratamento para infecção urinária com nitrofurantoína no momento do parto. Com 12 horas de vida, FR 72 mpm, sem disfunção. Hemoglobina 17 g/dl, hematócrito 51%, leucócitos 3.500/mm3 (8% bastões, 70% segmentados, 22% linfócitos), PCR 5 mg/l. Qual a provável etiologia da leucopenia no recém-nascido?", options: ["Prematuridade", "Infecção urinária da parturiente", "Diabetes gestacional", "Pré-eclâmpsia"], correctIndex: 3 },
  { id: "hcpa_2023_003", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "O nascimento de um neonato com 39 semanas transcorreu sem problemas. A mãe recebera espiramicina até a 36a semana por toxoplasmose gestacional, com IgM reagente coletada na 20a semana e teste de avidez de IgG de 80% (alta). Pesquisa de DNA por amniocentese não havia sido realizada. Diante desse quadro, qual a conduta mais adequada para o recém-nascido?", options: ["Não solicitar exames nem investigação, pois a infecção materna ocorreu antes da gestação.", "Solicitar sorologias IgM/IgG, fundoscopia, avaliação do SNC por USG ou TC; se normais, seguir apenas ambulatorialmente com repetição mensal dos títulos.", "Solicitar sorologias IgM/IgG, fundoscopia, avaliação do SNC por USG ou TC e punção lombar; se normais, seguir apenas ambulatorialmente.", "Solicitar sorologias IgM/IgG, fundoscopia, avaliação do SNC por USG ou TC e iniciar tratamento imediatamente com sulfadiazina, pirimetamina e ácido folínico."], correctIndex: 1 },
  { id: "hcpa_2023_004", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "O parto eletivo de uma gestante de 41 anos, com rotina pré-natal irregular (sem ecocardiografia fetal), foi realizado sem intercorrências. Ao nascimento, aspecto sindrômico e sopro cardíaco. Ecocardiograma aos 3 dias mostrou defeito do septo atrioventricular completo. Qual das síndromes é a mais frequente na presença dessa cardiopatia estrutural?", options: ["Síndrome de Noonan", "Síndrome de Down", "Síndrome de Edwards", "Síndrome de Patau"], correctIndex: 1 },
  { id: "hcpa_2023_005", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Diabetes gestacional, quando não adequadamente controlado durante o pré-natal, é causa de complicações para os recém-nascidos. Assinale a alternativa que contempla complicações relacionadas a essa condição materna.", options: ["Macrossomia, hipoglicemia, hipertrofia septal assimétrica e policitemia", "Macrossomia, hipocalcemia, policitemia e hemorragia intracraniana", "Microcefalia, anemia, hipoglicemia e hipertrofia septal assimétrica", "Anemia, hipocalcemia, ascite e síndrome do coração esquerdo hipoplásico"], correctIndex: 0 },
  { id: "hcpa_2023_006", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Assinale a alternativa que preenche, correta e respectivamente, as lacunas: O teste do reflexo vermelho (TRV) deve ser realizado .......... de vida e repetido pelo menos .......... ao ano durante as consultas de puericultura nos primeiros .......... da criança.", options: ["nas primeiras 24 horas – 1 vez – 2 anos", "nas primeiras 24 horas – 2 vezes – 2 anos", "nas primeiras 72 horas – 3 vezes – 3 anos", "na primeira semana – 2 vezes – 5 anos"], correctIndex: 2 },
  { id: "hcpa_2023_007", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente com 6 semanas de vida foi trazido à UBS por vômitos não biliosos, gradualmente crescentes, progredindo para vômitos em jato, logo após ou durante a alimentação. Continuava com fome, sem dor ou distensão abdominal. Hidratado e em bom estado geral. Pequena nodulação de cerca de 1 cm no QSD do abdômen. Por vezes, onda peristáltica visível do QSE para o direito. Qual a hipótese diagnóstica mais provável?", options: ["Doença do refluxo gastroesofágico", "Estenose pilórica", "Má rotação intestinal com volvo", "Intussuscepção"], correctIndex: 1 },
  { id: "hcpa_2023_008", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "De acordo com o PNI, estão indicadas 2 doses de vacina contra rotavírus, administradas por via oral. Assinale a alternativa que contempla uma orientação correta sobre essa vacina.", options: ["A 1a dose deve ser aplicada até a idade de 3 meses e 15 dias.", "Caso ocorra regurgitação ou vômito, deve-se repetir a aplicação.", "O intervalo mínimo entre as 2 doses é de 2 meses.", "A idade máxima para administração da 2a dose é de 8 meses e 15 dias."], correctIndex: 0 },
  { id: "hcpa_2023_009", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Que cuidado deve-se ter ao plotar, nos gráficos da Caderneta da Criança, as medidas antropométricas de uma criança de 20 meses, nascida com 35 semanas de idade gestacional (pré-termo)?", options: ["Utilizar as curvas de crescimento para prematuros.", "Utilizar as curvas de crescimento para crianças de 0-2 anos, sem ajustes.", "Utilizar as curvas de crescimento para crianças de 0-2 anos, descontando da idade cronológica 2 semanas.", "Utilizar as curvas de crescimento para crianças de 0-2 anos, descontando da idade cronológica 5 semanas."], correctIndex: 3 },
  { id: "hcpa_2023_010", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "As orientações para a introdução da alimentação complementar para uma criança saudável em aleitamento materno exclusivo estão contidas no Guia Alimentar de Crianças Brasileiras Menores de Dois Anos. Assim, esse tipo de alimentação deve ter início a partir dos .........., com alimentos in natura ou minimamente processados, ...........", options: ["4 meses – utilizando-se sal e açúcar em quantidades mínimas nas preparações", "4 meses – não se utilizando sal nem açúcar nas preparações até os 2 anos", "6 meses – utilizando-se sal e açúcar em quantidades mínimas nas preparações", "6 meses – utilizando-se sal em quantidade mínima sem a adição de açúcar nas preparações até os 2 anos"], correctIndex: 3 },
  { id: "hcpa_2023_011", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 4 meses, previamente hígido, foi transferido da Emergência para a Enfermaria com bronquiolite viral aguda por VSR. FR 42 mpm, tiragem subcostal leve, sibilos polifônicos expiratórios bilaterais. SpO2 95% em cateter nasal 1 l/min. RX: hiperinsuflação bilateral e opacidades intersticiais peri-hilares. Dieta por SNG, oxigênio por cateter e aspiração nasal se necessário. Que modificação na prescrição médica deve ser realizada na Enfermaria?", options: ["Aumento do fluxo de oxigênio pelo cateter nasal para 2 l/min", "Liberação da dieta por via oral", "Inclusão de salbutamol spray com espaçador (4 jatos, a cada 3 horas)", "Prescrição de fisioterapia respiratória (1 vez/dia)"], correctIndex: 1 },
  { id: "hcpa_2023_012", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 9 meses foi trazida à UBS para atendimento em puericultura. Ao aplicar o Instrumento dos Marcos de Desenvolvimento da Caderneta da Criança, constatou-se, pela 1a vez, que a criança não desenvolvera 2 habilidades para a faixa etária. Até então, vinha sendo capaz de dar conta de todos os itens. Como a criança deve ser classificada e qual a conduta a ser adotada?", options: ["Desenvolvimento adequado – Aplicar o Instrumento na próxima consulta.", "Desenvolvimento adequado – Aplicar o Instrumento em 30 dias.", "Alerta para o desenvolvimento – Aplicar o Instrumento em 30 dias.", "Provável atraso no desenvolvimento – Acionar a rede de atenção especializada para avaliação do desenvolvimento."], correctIndex: 2 },
  { id: "hcpa_2023_013", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Sabe-se que o TDAH é prevalente e que o diagnóstico é clínico, havendo critérios essenciais para seu correto reconhecimento. Assinale a alternativa que contempla o critério que necessariamente deverá ser identificado.", options: ["Início dos sintomas até os 10 anos", "Associação de desatenção e hiperatividade/impulsividade", "Resposta ao tratamento farmacológico com metilfenidato", "Existência de sintomas em mais de um ambiente"], correctIndex: 3 },
  { id: "hcpa_2023_014", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 2 anos foi trazido à Emergência por sua irmã mais velha (16 anos) por febre baixa e coriza. Ela referiu que ele vinha comendo o reboco da parede e a terra que ficava presa em seus sapatos. Palidez, temperatura axilar 37,8° C, hiperemia de orofaringe e sopro sistólico. Com base na história e exame físico, qual seria o resultado esperado do hemograma?", options: ["Hemoglobina de 6,5 g/l – VCM de 65 fl – CHCM de 23 pg – RDW de 18%", "Hemoglobina de 7 g/l – VCM de 80 fl – CHCM de 33 pg – RDW de 15%", "Hemoglobina de 8 g/l – VCM de 105 fl – CHCM de 30 pg – RDW de 18%", "Hemoglobina de 12 g/l – VCM de 80 fl – CHCM de 35 pg – RDW de 15%"], correctIndex: 0 },
  { id: "hcpa_2023_015", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando o caso do menino de 2 anos com pica (comendo reboco e terra), palidez e sopro sistólico, sugestivo de anemia ferropriva grave, que conduta é a mais adequada no momento?", options: ["Repor vitamina B12 e folato.", "Tratar o processo infeccioso com amoxicilina e solicitar avaliação cardiológica.", "Manejar o provável quadro viral com medicamentos sintomáticos e iniciar a administração de sulfato ferroso.", "Indicar transfusão sanguínea com concentrado de hemácias (10 ml/kg)."], correctIndex: 2 },
  { id: "hcpa_2023_016", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 4 anos foi trazido à consulta com febre alta, prostração, tosse e taquipneia. Temperatura axilar 39° C. Redução do murmúrio vesicular e do frêmito toracovocal, macicez à percussão e crepitantes no hemitórax direito. RX: broncogramas aéreos e opacidade de metade do hemitórax. Assinale a alternativa que contempla uma conduta adequada, além da antibioticoterapia.", options: ["Ultrassonografia do hemitórax direito e punção se houver derrame pleural livre, com qualquer volume.", "Ultrassonografia do hemitórax direito, punção e drenagem se houver derrame pleural livre, com volume de moderado a grande.", "Punção e drenagem, sem necessidade de outro exame de imagem.", "Punção e drenagem, sem necessidade de outro exame de imagem, e administração de fibrinolítico intrapleural."], correctIndex: 1 },
  { id: "hcpa_2023_017", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 5 anos foi trazida à Emergência por manchas roxas no corpo, há 5 dias, com cansaço e dor nas pernas ao caminhar. Pálida, apática, temperatura axilar 38,5° C. Hematomas no tronco e membros inferiores, adenopatias cervicais e axilares (2 cm), hepatoesplenomegalia 5 cm abaixo do rebordo costal. Sopro sistólico ejetivo. Qual o diagnóstico mais provável e a respectiva conduta?", options: ["Quadro viral por Epstein-Barr vírus com manejo sintomático e retorno ambulatorial programado (em 7 dias)", "Plaquetopenia transitória imune (PTI) da infância com indicação de início imediato de corticoterapia", "Leucemia aguda da infância e internação até o resultado dos exames", "Insuficiência cardíaca congestiva com indicação de avaliação cardiológica com urgência"], correctIndex: 2 },
  { id: "hcpa_2023_018", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 7 anos, previamente hígido, vacinas em dia, foi trazido à consulta por febre até 38o C há 24 horas, antecedida por 2 dias de dor de garganta, mialgias, tosse com sibilos e cefaleia frontal. Irmãos também com tosse e faringite. RX: infiltrado peri-hilar, mais evidente nos lobos inferiores, pequeno derrame pleural à direita. Qual a provável etiologia e qual o primeiro tratamento recomendado?", options: ["Micoplasma – azitromicina por via oral", "Estafilococo – oxacilina por via intravenosa", "Pneumococo – amoxicilina-clavulanato por via oral", "Vírus sincicial respiratório – oxigenoterapia"], correctIndex: 0 },
  { id: "hcpa_2023_019", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Escolar de 8 anos, com paralisia cerebral por hipóxia neonatal, traqueostomizado, foi trazido à consulta por episódio único de febre 38° C, aumento da frequência de aspiração da traqueostomia e secreção mais viscosa e amarelada. RX de tórax sem alterações. Iniciado amoxicilina-clavulanato. Em 72 horas, sintomas melhoraram significativamente e a irmã de 3 anos teve influenza A. Cultura de escarro: Pseudomonas aeruginosa sensível a ciprofloxacino e meropenem. Que conduta deve ser adotada?", options: ["Encaminhar o paciente para internação a fim de receber antibioticoterapia por via intravenosa.", "Manter amoxicilina-clavulanato até que se completem 10 dias de tratamento.", "Suspender amoxicilina-clavulanato e reavaliar o paciente se constatados sinais de gravidade.", "Substituir o antibiótico por ciprofloxacino e reavaliar o paciente se constatados sinais de gravidade."], correctIndex: 2 },
  { id: "hcpa_2023_020", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 14 anos foi trazido à Emergência após queda de bicicleta. Consciente, queixando-se de dores em todo o corpo. TC de crânio: coleção de sangue hiperdensa à esquerda, que não cruzava o tentório, mas não limitada pelas suturas. Ao retornar, teve perda transitória de consciência, hemiparesia à direita e dilatação pupilar ipsilateral. O declínio rápido de seu estado mental neste momento indica a necessidade de", options: ["administrar opioide contínuo intravenoso.", "iniciar corticoterapia intravenosa.", "realizar angiorressonância de crânio.", "realizar intubação endotraqueal."], correctIndex: 3 },
  { id: "hcpa_2023_021", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 36 anos, ciclos menstruais regulares e vida sexual ativa, veio à consulta com leucorreia e prurido, quadro iniciado há 3 dias, recorrente todos os meses. Exame a fresco revelou lâmina característica. Com base no quadro, assinale a assertiva correta.", options: ["O pH da vagina deve estar < 4.", "Os sintomas pioram no período pré-ovulatório.", "Os sintomas pioram após a relação sexual.", "Os sintomas costumam melhorar após a menstruação."], correctIndex: 2 },
  { id: "hcpa_2023_022", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 62 anos consultou por perda urinária aos pequenos esforços, sem urgência urinária, não conseguindo segurar a urina até chegar ao banheiro. Uso de losartana, hidroclorotiazida e insulina há mais de 10 anos. Sem distopia urinária, mas perda no pequeno esforço à manobra de Valsalva, pressão de perda de 80 cmH2O e resíduo urinário de 400 ml. IMC 34 kg/m². O diagnóstico mais provável é incontinência urinária", options: ["por transbordamento.", "por deficiência esfincteriana.", "de desvio.", "transitória."], correctIndex: 0 },
  { id: "hcpa_2023_023", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 53 anos, com menopausa cirúrgica (histerectomia) aos 49 anos, veio à consulta com calorões, sudorese e humor lábil. Tratamento controlado para HAS e DM. Histórico de câncer de mama aos 40 anos, com revisões sempre normais, e osteoporose. Com base no quadro, pode-se afirmar que a paciente", options: ["apresenta 3 contraindicações à terapia hormonal (TH): HAS, DM e câncer de mama.", "pode receber TH (uso de estrogênio isolado, por ser histerectomizada), desde que por via transdérmica.", "pode fazer uso de tibolona, por ter tratado o câncer de mama há mais de 10 anos, sem sinal de recidiva.", "apresenta contraindicação à TH, por seu histórico de câncer de mama."], correctIndex: 3 },
  { id: "hcpa_2023_024", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O uso de acetato de medroxiprogesterona de depósito (150 mg/ml intramuscular) tem poucas contraindicações. Esse contraceptivo não pode ser usado na vigência de", options: ["hipertensão arterial sistêmica controlada (níveis < 160/100 mmHg).", "trombose venosa profunda.", "diabetes melito tipo 2 controlado.", "uso de anticonvulsivantes."], correctIndex: 1 },
  { id: "hcpa_2023_025", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 37 anos, usuária de anticoncepcional oral combinado (AOC) com regularidade há 6 anos, bem adaptada. Queixou-se de cefaleia nos dias que antecediam a menstruação, quadro iniciado há 2 anos, com náuseas e vômitos, usava sumatriptano e propranolol profilático em baixa dose. Com base no quadro, assinale a assertiva correta.", options: ["A paciente tem contraindicação ao uso de AOC pelo conteúdo progestogênico do composto.", "O uso de AOC aumenta o risco de acidente vascular cerebral isquêmico.", "O uso de anticoncepção combinada, por via transdérmica e vaginal, reduz o risco de trombose venosa/arterial.", "Apenas métodos não hormonais estão indicados."], correctIndex: 1 },
  { id: "hcpa_2023_026", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 20 anos, com ciclos menstruais irregulares, consultou por não menstruar há 6 meses. Sem atividade sexual há 2 anos, aborto espontâneo aos 15 anos, sem curetagem. IMC 18,5 kg/m². b-hCG negativo, FSH 0,3 mUI/ml (VR 3-10), prolactina 15 ng/ml (VR 5-25). Com base no quadro, qual a hipótese diagnóstica mais provável?", options: ["Amenorreia hipotalâmica", "Sinéquia uterina", "Síndrome dos ovários policísticos", "Insuficiência ovariana"], correctIndex: 0 },
  { id: "hcpa_2023_027", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Conforme as Diretrizes Brasileiras para o Rastreamento do Câncer do Colo do Útero, referentemente ao exame citopatológico (CP) do colo uterino, paciente atendida na UBS deve ser encaminhada para colposcopia se, em", options: ["2 CPs com amostra satisfatória, apresentar células escamosas e metaplásicas imaturas.", "1 CP com amostra insatisfatória, a leitura for prejudicada pela intensa superposição celular.", "1 CP com amostra satisfatória, apresentar lesão intraepitelial de baixo grau (LIBG).", "1 CP com amostra satisfatória, apresentar células glandulares atípicas (AGC)."], correctIndex: 3 },
  { id: "hcpa_2023_028", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 42 anos, casada e com 3 filhos, em uso de DIU de cobre, veio à consulta com sangramento intermitente, última revisão ginecológica há 5 anos. PA 130/85 mmHg, peso 60 kg, altura 168 cm; mamas, abdômen e vulva sem particularidades. Exame especular: colo com lesão de aspecto tumoral, 1 cm. Foi realizada .......... . Com base no resultado, .......... , foi indicada ...........", options: ["coleta de material para exame citopatológico – lesão intraepitelial de alto grau – conização", "colposcopia – lesão sugestiva de câncer invasor – histerectomia extrafascial", "biópsia – carcinoma invasor – realização de estadiamento", "biópsia – adenocarcinoma invasor – histerectomia extrafascial"], correctIndex: 2 },
  { id: "hcpa_2023_029", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre a vacina contra o papilomavírus humano.", options: ["A vacina protege contra as infecções virais assintomáticas, mas não tem impacto no câncer de colo de útero.", "A vacina está indicada apenas para quem comprovadamente não teve contato com o vírus.", "Não é permitido vacinar mulheres com diagnóstico prévio de neoplasia intraepitelial vulvar.", "A vacina pode ser realizada em outras faixas etárias além daquelas contempladas pelo PNI, do Ministério da Saúde."], correctIndex: 3 },
  { id: "hcpa_2023_030", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Jovem de 17 anos veio à consulta com ciclos menstruais irregulares desde a menarca (14 anos), piora da acne e aumento de pelos no rosto e corpo no último ano. M3 e P5 (Tanner), escore de Ferriman de 15. Mede 158 cm e pesa 66 kg. Para o diagnóstico diferencial entre síndrome dos ovários policísticos e hiperplasia adrenal congênita não clássica, qual o exame mais adequado?", options: ["Dosagem de 17-OH progesterona", "Dosagem de testosterona livre", "Ultrassonografia abdominal total", "Ultrassonografia pélvica"], correctIndex: 0 },
  { id: "hcpa_2023_031", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "A regra de Nägele pode ser utilizada para o cálculo da data provável do parto. Considerando que uma gestante informou ter sido 01 de junho de 2022 a data da última menstruação, a data provável do parto será", options: ["26 de fevereiro de 2023.", "01 de março de 2023.", "04 de março de 2023.", "08 de março de 2023."], correctIndex: 3 },
  { id: "hcpa_2023_032", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre assistência pré-natal.", options: ["No exame físico da gestante, a ausculta dos batimentos cardiofetais pode ser feita a partir da 6a semana de gestação com sonar Doppler.", "No 3o trimestre de gestação, o decúbito dorsal materno pode levar ao efeito Poseiro, que se caracteriza por bradicardia materna e taquicardia fetal.", "Toda gestante deve receber pelo menos 1 dose da vacina dTpa, mesmo que tenha recebido dTpa na gestação anterior e dT na gestação atual.", "A presença de anticorpos IgG para toxoplasmose com baixa avidez no 1o trimestre de gestação indica infecção antiga e exclui infecção aguda nos últimos 3 meses."], correctIndex: 2 },
  { id: "hcpa_2023_033", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Que fármaco, dentre os abaixo, pode ser utilizado durante a gestação em pacientes com epilepsia?", options: ["Lamotrigina", "Hidantoína", "Fenobarbital", "Ácido valproico"], correctIndex: 0 },
  { id: "hcpa_2023_034", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta de 20 anos, com 16 semanas de gestação, trouxe ao Ambulatório de Pré-natal uma ultrassonografia obstétrica mostrando feto com anencefalia. Manifestou o desejo de interrupção imediata da gestação. Qual a conduta mais adequada neste momento?", options: ["Encaminhar a paciente ao Centro Obstétrico para realizar a interrupção da gestação.", "Solicitar nova ultrassonografia e, confirmado o diagnóstico, interromper a gestação.", "Solicitar autorização judicial para interrupção da gestação.", "Negar o pedido de interrupção da gestação, pois a paciente tem menos de 25 anos."], correctIndex: 1 },
  { id: "hcpa_2023_035", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 26 anos, G3P2, veio à consulta na 18a semana de gestação. Partos com nascimentos em 34 e 30 semanas, com contrações e ruptura de membranas. Negou uso de medicamentos. Urocultura: Streptococcus do grupo βeta (30.000 colônias/ml). Colo grosso, fechado e posterior, BCF 132 bpm. Qual a conduta mais adequada?", options: ["Observar clinicamente a paciente e repetir a urocultura em 7 dias.", "Prescrever apenas ampicilina por via oral.", "Prescrever progesterona por via vaginal e repetir a urocultura.", "Prescrever progesterona por via vaginal e ampicilina por via oral."], correctIndex: 2 },
  { id: "hcpa_2023_036", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta de 18 anos, com 28 semanas de gestação, apresentou convulsão tônico-clônica generalizada na UBS. PA 130/90 mmHg, sem proteinúria. Mesmo desacompanhada, deverá ser imediatamente encaminhada a uma maternidade de alto risco. Para evitar convulsões durante o transporte, a conduta mais adequada é administrar", options: ["sulfato de magnésio intramuscular.", "sulfato de magnésio intravenoso.", "diazepam intramuscular.", "fenitoína intravenosa."], correctIndex: 0 },
  { id: "hcpa_2023_037", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente com 37 semanas de gestação procurou a Emergência Obstétrica por sangramento vaginal, pré-natal de risco habitual sem intercorrências. PA 140/90 mmHg, FC 110 bpm, altura uterina 32 cm, 5 contrações dolorosas em 10 minutos, útero hipertônico, BCF 100 bpm. Sangramento pelo orifício cervical externo, sem dilatação. Qual o diagnóstico mais provável e a conduta a ser seguida?", options: ["Placenta prévia – ultrassonografia para confirmação do diagnóstico", "Descolamento prematuro de placenta – cesariana de urgência", "Ruptura uterina – cesariana de urgência", "Vasa prévia – ultrassonografia para definir a origem fetal do sangramento"], correctIndex: 1 },
  { id: "hcpa_2023_038", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente no 3o trimestre de gestação, Rh-isoimunizada, realizou ultrassonografia obstétrica com Doppler. Que parâmetro ultrassonográfico deve ser considerado para avaliar anemia fetal?", options: ["Relação sístole/diástole das artérias uterinas", "Índice de pulsatilidade da artéria umbilical", "Pico de velocidade sistólica da artéria cerebral média", "Índice de resistência do ducto venoso"], correctIndex: 2 },
  { id: "hcpa_2023_039", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre episiotomia.", options: ["Deve ser realizada de rotina em partos de primigestas.", "Deve ser evitada em partos instrumentados, pois aumenta o risco de laceração do esfíncter anal.", "Deve-se dar preferência pela técnica mediana.", "Está indicada se houver necessidade de abreviar o 2o período do parto em casos de condição fetal não tranquilizadora."], correctIndex: 3 },
  { id: "hcpa_2023_040", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primípara, parto vaginal sem intercorrências há 2 dias, lóquios sanguinolentos. Hidratada e hipocorada 1+/4+, PA 110/70 mmHg. Mamas flácidas com saída de colostro, útero contraído, 2 cm abaixo da cicatriz umbilical. Que conduta está indicada?", options: ["Orientar a alta hospitalar, por tratar-se de um puerpério fisiológico.", "Manter a paciente internada e intensificar o aleitamento até a apojadura.", "Solicitar realização de hemograma e ultrassonografia para afastar a suspeita de restos placentários.", "Realizar revisão do colo uterino, para afastar a suspeita de laceração no trajeto do parto."], correctIndex: 0 },
  { id: "hcpa_2023_041", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 65 anos, com prostatectomia há 1 mês, foi submetido a procedimento com anestesia geral para troca do cateter duplo J. Procedimento de 20 minutos, sem complicações. Na Sala de Recuperação, redução do sensório, FC 125 bpm, PA 84/35 mmHg, FR 26 mpm, temperatura axilar 37,8o C, SpO2 90%. Qual dos manejos é o mais apropriado?", options: ["Acessar imediatamente via aérea definitiva com intubação e transferir o paciente para o CTI.", "Iniciar administração de cristaloide em bolo e de vasopressor, coletar material para exames culturais e prescrever antibiótico de amplo espectro.", "Iniciar analgesia eficiente com morfina e solicitar angiotomografia e dosagem de D-dímeros.", "Encaminhar imediatamente o paciente para tomografia computadorizada abdominal para descartar complicação relacionada ao procedimento."], correctIndex: 1 },
  { id: "hcpa_2023_042", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 83 anos, com hipertensão e cardiopatia isquêmica (stent há 10 anos), assintomática, mas com limitação funcional por dores articulares, será submetida a cirurgia de catarata. Uso de AAS, betabloqueador e hidroclorotiazida. PA 140/80 mmHg, FC 89 bpm. Assinale a assertiva correta sobre o manejo pré-operatório dessa cirurgia.", options: ["A paciente pode ser liberada para o procedimento sem avaliações adicionais.", "AAS e betabloqueador devem ser suspensos antes do procedimento.", "Exames pré-operatórios de rotina para idade (hemograma, função renal, raio X de tórax, eletrocardiografia e testes de coagulação) devem ser solicitados.", "Eletrocardiografia de esforço (ergometria) é a primeira opção para estratificação do risco cardíaco."], correctIndex: 0 },
  { id: "hcpa_2023_043", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente foi encaminhado à Emergência por suspeita de oclusão arterial aguda em membro inferior. Que achado do exame físico corrobora a hipótese diagnóstica?", options: ["Edema na panturrilha e no pé", "Rubor restrito aos pododáctilos", "Cianose não fixa de pododáctilos com palidez dos demais segmentos do pé", "Presença de pulso tibial posterior e tibial anterior e ausência de pulso pedioso"], correctIndex: 2 },
  { id: "hcpa_2023_044", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente com hemiparesia direita por AVC há 2 meses apresentou, à angiotomografia, oclusão na artéria carótida interna esquerda, estenose de 60% na artéria carótida interna direita e artérias vertebrais pérvias e sem estenoses relevantes. O tratamento mais adequado é", options: ["anticoagulação.", "uso de antiagregante plaquetário e estatina.", "angioplastia com stent na carótida interna direita.", "endarterectomia na carótida interna esquerda."], correctIndex: 1 },
  { id: "hcpa_2023_045", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre isquemia mesentérica aguda devido a êmbolos liberados a partir das cavidades cardíacas.", options: ["Fibrilação atrial é a condição cardíaca mais comum associada a embolia.", "Os êmbolos ocluem os primeiros ramos jejunais na maioria dos casos.", "Quando ocorre embolia na artéria mesentérica superior, o quadro clínico é insidioso devido à ampla circulação colateral.", "A tríade dor abdominal, evacuação sanguinolenta e hipotensão está presente em mais de 2/3 dos casos."], correctIndex: 0 },
  { id: "hcpa_2023_046", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Associe os métodos diagnósticos (Manometria esofágica, Ecoendoscopia, pHmetria esofágica de 24 horas, Endoscopia digestiva alta) às respectivas situações clínicas (Doença do refluxo gastroesofágico; Acalásia de esôfago; Gastrite por refluxo alcalino; Leiomioma de esôfago). A sequência numérica correta, de cima para baixo, é", options: ["1 – 4 – 3 – 2", "2 – 4 – 3 – 1", "3 – 1 – 2 – 4", "3 – 1 – 4 – 2"], correctIndex: 3 },
  { id: "hcpa_2023_047", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 80 anos, tabagista, com demência leve, usuária crônica de AINE por artrose do joelho, foi trazida à Emergência por dor abdominal difusa há 36 horas, sinais de irritação peritoneal, taquicardia, hipotensão, confusão mental e sinais de má perfusão periférica. Diagnóstico de abdômen agudo perfurativo. Qual a principal hipótese diagnóstica, abordagem cirúrgica e tratamento?", options: ["Úlcera péptica perfurada – videolaparoscopia – ulcerorrafia com vagotomia troncular", "Úlcera péptica perfurada – laparotomia – ulcerorrafia", "Isquemia intestinal – videolaparoscopia – enterectomia", "Diverticulite aguda perfurada – laparotomia – colectomia com colostomia (sem anastomose)"], correctIndex: 1 },
  { id: "hcpa_2023_048", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 60 anos, assintomática, realizou ultrassonografia abdominal que identificou pólipo de 0,7 cm na vesícula biliar. Em tratamento para colangite esclerosante primária. Que conduta é a mais adequada?", options: ["Realizar acompanhamento anual com ultrassonografia abdominal.", "Realizar colecistectomia videolaparoscópica.", "Realizar ultrassonografia endoscópica para avaliar a base da lesão polipoide.", "Solicitar dosagens de CEA e CA 19-9."], correctIndex: 1 },
  { id: "hcpa_2023_049", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente feminina, de 50 anos, 90 kg, 169 cm, apresentou dor no abdômen superior. Lipase 3.000 U/l, ALT 300 U/l, hemoglobina 11 g/dl, leucograma 12.000/mm3 sem desvio. USG abdominal: múltiplos cálculos na vesícula biliar com colédoco medindo 5 mm. Assinale a assertiva que contempla a conduta mais adequada.", options: ["Indicar hidratação vigorosa com ringer lactato (bolo de 20 ml/kg em 2 horas seguido de 3 ml/kg/hora).", "Realizar tomografia computadorizada abdominal com contraste para diagnóstico.", "Realizar colangiografia endoscópica por suspeita de coledocolitíase.", "Realizar colecistectomia videolaparoscópica com colangiografia na mesma internação."], correctIndex: 3 },
  { id: "hcpa_2023_050", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "As estruturas anatômicas A, B e C correspondem aos principais elementos contidos no porta hepatis. Qual a distribuição anatômica mais frequentemente encontrada?", options: ["A – Artéria hepática, B – Via biliar principal, C – Veia porta", "A – Veia porta, B – Artéria mesentérica superior, C – Via biliar principal", "A – Artéria mesentérica superior, B – Via biliar principal, C – Veia porta", "A – Via biliar principal, B – Artéria hepática, C – Veia porta"], correctIndex: 3 },
  { id: "hcpa_2023_051", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 55 anos, com eliminação espontânea de sangue vivo e muco na roupa íntima há 3 anos. Ao exame, hemorroida interna prolapsada não redutível. Assinale a alternativa que contempla o tratamento indicado.", options: ["Orientações dietéticas e higiênicas somente", "Fotocoagulação com infravermelho", "Hemorroidectomia", "Ligadura elástica"], correctIndex: 2 },
  { id: "hcpa_2023_052", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente submetido a herniorrafia incisional mediana infraumbilical, com tela, há 20 dias, foi trazido à Emergência por febre de 38,5o C. FC 110 bpm, PA 100/60 mmHg. Eritema intenso ao redor da ferida operatória, dor muito forte, drenagem de secreção purulenta em moderado volume à expressão manual. Qual o tratamento mais indicado?", options: ["Drenagem da secreção purulenta por abertura dos pontos da ferida operatória e coleta da secreção para cultura", "Drenagem da secreção purulenta por abertura dos pontos da ferida operatória, coleta da secreção para cultura e antibioticoterapia", "Exploração cirúrgica da ferida operatória com debridamento de tecidos desvitalizados, coleta da secreção para cultura, remoção da tela e antibioticoterapia", "Exploração cirúrgica da ferida operatória com debridamento de tecidos desvitalizados, coleta da secreção para cultura, manutenção da tela e antibioticoterapia"], correctIndex: 2 },
  { id: "hcpa_2023_053", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 64 anos veio à Emergência por dor abdominal em cólica e vômitos há 12 horas. Uma evacuação normal seguida de diarreica logo após, sem mais eliminação de gases ou fezes. Laparotomia por ferimento penetrante abdominal com lesão hepática e intestinal há mais de 20 anos. Distensão abdominal concentrada no epigástrio, timpânico. Ampola retal vazia. RX: distensão hidroaérea com imagem em pilha de moedas e níveis hidroaéreos em diferentes alturas. Assinale a assertiva correta sobre esse quadro clínico.", options: ["Presença de níveis hidroaéreos sugere obstrução intestinal baixa.", "Vômitos no início do quadro e ausência de grande distensão sugerem obstrução intestinal alta.", "O paciente deve ter válvula ileocecal competente, o que explicaria o quadro clínico e os achados radiológicos.", "A causa mais provável do quadro é íleo biliar, por ter sido negligenciado o tratamento da colelitíase."], correctIndex: 1 },
  { id: "hcpa_2023_054", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Que malformação broncopulmonar não apresenta comunicação com a via aérea traqueobrônquica normal, cuja nutrição é proveniente de um vaso arterial sistêmico anômalo, geralmente oriundo da aorta abdominal ou torácica?", options: ["Malformação congênita de via aérea e pulmão (MCVAP)", "Enfisema lobar congênito", "Sequestro pulmonar", "Cisto broncogênico intrapulmonar"], correctIndex: 2 },
  { id: "hcpa_2023_055", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre a cirurgia da unha.", options: ["Quando há fratura da falange distal associada a um hematoma subungueal, ela é considerada uma fratura exposta.", "O tratamento do hematoma subungueal costuma ser conservador.", "A drenagem de um hematoma subungueal por perfuração geralmente está contraindicada.", "O uso de antirretrovirais previne paroníquia em pacientes com vírus da imunodeficiência humana."], correctIndex: 0 },
  { id: "hcpa_2023_056", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 35 anos, com queimaduras de mais de 30% do corpo, foi internado na Unidade de Queimados, já tendo recebido os primeiros atendimentos adequadamente. Para quantificar a reposição volêmica após 24 horas do manejo inicial, qual a principal referência a ser utilizada?", options: ["Superfície corporal queimada", "Débito urinário", "Pressão venosa central", "Pressão arterial média"], correctIndex: 1 },
  { id: "hcpa_2023_057", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente de 33 anos, tabagista, encaminhado da UPA para o Ambulatório por tosse há 4 semanas, inapetência, calafrios eventuais e discreto emagrecimento. RX de tórax revelou volumoso derrame pleural à direita com compressão de metade do pulmão, sem desvio do mediastino. Optou-se por toracocentese. Assinale a assertiva correta sobre a análise do líquido pleural.", options: ["Tabagismo e emagrecimento apontam para derrame neoplásico, sendo a análise citopatológica do líquido suficiente para o diagnóstico.", "Análises de proteínas, pH, LDH e glicose pleurais estabelecem se o líquido é um transudato ou um exsudato.", "Análises macroscópica (aspecto), bioquímica e bacteriológica auxiliam na definição de derrame complicado/não complicado e na definição da conduta terapêutica.", "Exame citológico diferencial auxilia o raciocínio diagnóstico em quadros infecciosos, tendo menor importância se a suspeita for neoplásica."], correctIndex: 2 },
  { id: "hcpa_2023_058", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre fraturas de costelas.", options: ["Pneumonia é a complicação mais frequente e está diretamente relacionada ao número de costelas quebradas e à idade do paciente.", "Hemotórax é a complicação mais frequente e, na maioria das vezes, subdiagnosticada, levando a maior número de complicações, como empiema.", "Pneumotórax associado sem hemotórax deve ser tratado conservadoramente.", "Controle adequado da dor diminui o risco de coágulos retidos, mas não diminui a probabilidade de pneumonia."], correctIndex: 0 },
  { id: "hcpa_2023_059", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Paciente masculino, de 20 anos, sofreu trauma craniano, com fratura cominutiva com afundamento parietal. Ferimento cortocontuso do couro cabeludo sobre o local do afundamento. Que conduta é a mais adequada?", options: ["Realizar tratamento cirúrgico com debridamento da ferida e remoção dos fragmentos ósseos.", "Realizar tratamento conservador, sem emprego de antibióticos.", "Instituir antibioticoprofilaxia e realizar sutura simples do ferimento.", "Instituir tratamento com antibióticos e corticosteroides."], correctIndex: 0 },
  { id: "hcpa_2023_060", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Hipospadia se caracteriza", options: ["pela localização ectópica do meato uretral, abaixo do centro da glande.", "pela curvatura peniana ventral com um meato uretral ortotópico.", "por um prepúcio intacto.", "pelo alto risco de anomalias associadas, além do trato geniturinário."], correctIndex: 0 },
  { id: "hcpa_2023_061", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Paciente masculino, de 30 anos, com diabetes melito e hipertensão arterial de difícil controle, veio à consulta de revisão. Achados de mãos com pele espessada e imagem dentária característica sugerem qual diagnóstico?", options: ["Síndrome de Cushing", "Insuficiência adrenal", "Acromegalia", "Doença de Paget"], correctIndex: 2 },
  { id: "hcpa_2023_062", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Paciente masculino, de 54 anos, procurou a Emergência por dor retroesternal moderada há 3 horas, sem irradiação, atualmente sem dor. HAS e dislipidemia em tratamento. Estável, Killip I. Troponina I ultrassensível 12 pg/ml na admissão e 154 pg/ml após 3 horas (VR < 5 pg/ml). Que diagnóstico é o mais provável?", options: ["Angina instável", "Infarto agudo do miocárdio com supradesnivelamento do segmento ST na parede lateral", "Infarto agudo do miocárdio com supradesnivelamento do segmento ST na parede anterior", "Infarto agudo do miocárdio sem supradesnivelamento do segmento ST"], correctIndex: 3 },
  { id: "hcpa_2023_063", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Paciente de 37 anos apresentou hipertensão arterial diastólica (125/100 mmHg) em revisão anual. Eco-Doppler de artérias renais mostrou estenose > 60% na artéria renal direita. Qual a etiologia mais provável e qual o tratamento adequado?", options: ["Displasia fibromuscular – tratamento clínico com anti-hipertensivos", "Displasia fibromuscular – angioplastia de artéria renal", "Aterosclerose – angioplastia com implante de stent", "Aterosclerose – tratamento clínico com anti-hipertensivos"], correctIndex: 1 },
  { id: "hcpa_2023_064", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente de 29 anos, previamente hígido, veio à consulta para revisão geral da pele. Lesão com crescimento progressivo no ombro esquerdo, surgida há 2 anos: mancha hiperpigmentada em tons de marrom e preto, assimétrica, bordas irregulares, 1 cm, associada a nevo pré-existente. Com base no quadro, assinale a assertiva correta.", options: ["Trata-se de uma lesão suspeita de melanoma nodular.", "Espessura tumoral definida ao exame anatomopatológico é o principal índice prognóstico para esse tipo de tumor.", "Dermatoscopia não tem utilidade na avaliação de lesões pigmentadas da pele.", "Biópsia incisional é a abordagem inicial mais adequada."], correctIndex: 3 },
  { id: "hcpa_2023_065", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Paciente de 22 anos, com diabetes melito tipo 1 desde os 5 anos, internada para tratamento de pielonefrite aguda, má adesão ao tratamento e uso irregular das insulinas. HbA1c 11%. Insulina NPH e lispro em esquema fixo. Às 10h, glicemia capilar 45 mg/dl, corrigida com glicose oral; antes do almoço, 102 mg/dl. Qual das alternativas contempla a conduta correta quanto às insulinas antes do almoço?", options: ["Não administrar as insulinas NPH e lispro antes do almoço.", "Não administrar a insulina NPH, mas administrar a lispro antes do almoço.", "Administrar a insulina NPH e não administrar a lispro antes do almoço.", "Administrar normalmente as insulinas NPH e lispro antes do almoço."], correctIndex: 3 },
  { id: "hcpa_2023_066", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Assinale a assertiva correta sobre o tratamento da obesidade.", options: ["A perda calórica resultante da prática de exercício físico é mais importante do que a decorrente de restrição calórica dietética.", "A recomendação para a realização de pequenas refeições de 3 em 3 horas está embasada em resultados de ensaios clínicos randomizados.", "A inclusão de café da manhã no plano alimentar não resultou em maior perda de peso segundo ensaios clínicos randomizados.", "O uso de medicamentos, como agonistas do GLP-1, deve ser reservado para pacientes com IMC > 30 kg/m², não devendo seu uso ultrapassar 6 meses."], correctIndex: 2 },
  { id: "hcpa_2023_067", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Associe as doenças inflamatórias intestinais (Doença de Crohn, Retocolite ulcerativa, Ambas) às apresentações endoscópicas/clínicas: pode acometer qualquer segmento do trato digestivo; acomete a mucosa colônica em padrão contínuo; pico de incidência bimodal; erosões e úlceras intercaladas com áreas de mucosa normal; pode se manifestar com deficiência de vitamina B12. A sequência numérica correta, de cima para baixo, é", options: ["1 – 2 – 1 – 1 – 3", "1 – 2 – 3 – 1 – 1", "2 – 1 – 3 – 2 – 1", "2 – 2 – 2 – 1 – 3"], correctIndex: 1 },
  { id: "hcpa_2023_068", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Assinale a assertiva correta sobre quedas em idosos.", options: ["São fatores de risco para quedas ser do sexo masculino e apresentar depressão.", "Idosos frágeis tendem a apresentar mais quedas em ambientes externos.", "Após uma queda da própria altura, independentemente das circunstâncias em que ocorreu, é necessário prosseguir com exames complementares para descartar causas cardíacas.", "O fator de risco de maior importância para novas quedas é ter caído no último ano."], correctIndex: 3 },
  { id: "hcpa_2023_069", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Paciente de 18 anos foi encaminhada ao Ambulatório de Hematologia para investigação de anemia hipoproliferativa devido a microcitose e anisocitose ao hemograma. Diante da hipótese de anemia ferropriva, que alteração do exame físico poderia corroborar esse diagnóstico?", options: ["Lesões cutâneas hipocrômicas", "Diminuição do reflexo patelar", "Queilite angular", "Anel de Kayser-Fleischer"], correctIndex: 2 },
  { id: "hcpa_2023_070", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Paciente masculino, de 59 anos, com alcoolismo desde os 20 anos e uso de drogas injetáveis dos 20 aos 23 anos, procurou a Emergência por aumento de volume abdominal e letargia. Eritema palmar, aranhas vasculares, icterícia, confusão mental, flapping; macicez móvel, esplenomegalia, circulação colateral. Hemoglobina 10,2 g/dl, plaquetas 44.000/mm3, creatinina 1,47 g/dl, bilirrubina total 4,1 mg/dl, TP 18,5 s (64%), INR 1,97, albumina 2,7 g/dl. Assinale a assertiva correta sobre a avaliação diagnóstica e a conduta inicial.", options: ["A alteração da função renal pode estar relacionada a síndrome hepatorrenal, porém esse é um diagnóstico de exclusão após terem sido afastadas e corrigidas condições associadas, como hipovolemia e/ou alteração hemodinâmica, suspensão de diuréticos e expansão volêmica com albumina.", "Paracentese diagnóstica deve ser realizada em caso de dor abdominal e/ou febre, para investigar peritonite bacteriana espontânea.", "Dosagem de amônia sérica deve ser realizada para o diagnóstico de encefalopatia hepática, por ter relação direta com a intensidade das manifestações clínicas.", "Peritonite bacteriana espontânea ocorre devido à translocação bacteriana e, para seu diagnóstico, é necessário identificar > 500 polimorfonucleares/µl no líquido de ascite."], correctIndex: 2 },
  { id: "hcpa_2023_071", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Pessoa vivendo com HIV, em tratamento antirretroviral regular, CD4 600 células/mm3 e carga viral indetectável, assintomática. VDRL de rotina: título 1:8 e FTA-Abs positivo. Tratamento com penicilina benzatina 2.400.000 UI por 3 semanas. Repetiu VDRL 1 mês após: mesmo título (1:8). Qual a conduta mais adequada?", options: ["Realizar punção liquórica para descartar neurossífilis.", "Realizar tratamento com penicilina cristalina intravenosa por 14 dias.", "Repetir o tratamento com penicilina benzatina.", "Repetir o exame de VDRL em 3 meses após tratamento da sífilis."], correctIndex: 3 },
  { id: "hcpa_2023_072", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Urgência e Emergência", text: "Paciente masculino, de 60 anos, apresentou parada cardiorrespiratória extra-hospitalar. Reanimação iniciada no local, 3 choques com DEA. Ao chegar o SAMU, irresponsivo, mas com pulso, FR 30 mpm, PA sistólica 70 mmHg, SpO2 80% em ar ambiente. Como deve ser a continuidade do cuidado antes de transportá-lo para o hospital?", options: ["Oferecer oxigênio suplementar por máscara com reservatório e cristaloide gelado intravenoso.", "Oferecer oxigênio suplementar por máscara com reservatório e cristaloide gelado e amiodarona contínua intravenosos.", "Intubar e administrar vasopressor e amiodarona contínua intravenosos.", "Intubar e administrar cristaloide e vasopressor intravenosos."], correctIndex: 3 },
  { id: "hcpa_2023_073", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Assinale a assertiva correta sobre o manejo preventivo de litíase renal recorrente.", options: ["A prevenção requer uso de medicação contínua, independentemente do tipo de cálculo.", "O consumo de fluidos deve ser suficiente para manter o débito urinário em 2 litros/dia.", "O consumo de cálcio deve ser inferior a 1.000 mg/dia, e o de sódio, superior a 100 mEq/dia.", "O consumo de frutas e vegetais deve ser evitado pelo risco de formação de cálculos de oxalato de cálcio."], correctIndex: 1 },
  { id: "hcpa_2023_074", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Paciente de 35 anos procurou a Emergência por febre, dor lombar e disúria. Prostrada, temperatura axilar 38° C, sinais vitais estáveis. Punho-percussão lombar positiva à direita. Que conduta é a mais adequada?", options: ["Solicitar ultrassonografia de vias urinárias e iniciar antibioticoterapia empírica por via oral.", "Solicitar urocultura, iniciar antibioticoterapia empírica por via oral e liberar a paciente.", "Internar a paciente, solicitar urocultura e aguardar o resultado do exame para iniciar o tratamento.", "Internar a paciente, solicitar urocultura e iniciar antibioticoterapia por via intravenosa de amplo espectro."], correctIndex: 1 },
  { id: "hcpa_2023_075", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Qual dos seguintes achados do exame físico neurológico indica lesão da via piramidal?", options: ["Hipertonia plástica", "Rigidez cérea", "Sinal de Romberg", "Clônus sustentado"], correctIndex: 3 },
  { id: "hcpa_2023_076", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Que condição não constitui contraindicação para trombólise intravenosa?", options: ["Uso de varfarina com INR > 1,7", "Suspeita de hemorragia subaracnóidea", "Presença de endocardite bacteriana", "Presença de meningioma"], correctIndex: 3 },
  { id: "hcpa_2023_077", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Oncologia", text: "Paciente feminina, de 63 anos, procurou a Emergência por dor lombar de forte intensidade há 2 dias, piora progressiva, com parestesias nos membros inferiores. Nódulo na mama esquerda crescendo há mais de 2 anos sem investigação, nódulo axilar surgido há 3 meses. Regular estado geral, fácies de dor, dificuldade de deambulação. Força preservada nos membros inferiores. Diante do quadro clínico, qual a conduta mais adequada?", options: ["Fazer biópsia do nódulo da mama esquerda com urgência, pois, sem o diagnóstico de uma possível neoplasia maligna de mama, não há como definir os demais problemas e tratamentos para a paciente.", "Prescrever corticosteroide sistêmico e analgésico e encaminhar a paciente para investigação adicional em serviço especializado da instituição.", "Tratar a dor da paciente e solicitar tomografia computadorizada ou ressonância magnética da coluna lombossacra para diagnóstico de possível compressão medular, uma vez que há urgência em iniciar o tratamento caso seja esse o problema.", "Iniciar tratamento empírico para uma provável neoplasia metastática de mama, enquanto são solicitados exames de estadiamento e biópsia."], correctIndex: 2 },
  { id: "hcpa_2023_078", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente feminina, de 65 anos, procurou a Emergência com dor torácica à esquerda, iniciada há cerca de 1 mês. Ausência de murmúrios vesiculares à esquerda. Com base nos dados e na radiografia de tórax, qual a hipótese diagnóstica menos provável?", options: ["Derrame pleural por insuficiência cardíaca", "Derrame pleural metastático", "Tuberculose pleural", "Mesotelioma pleural"], correctIndex: 0 },
  { id: "hcpa_2023_079", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente masculino, de 50 anos, veio à consulta com despertares frequentes durante o sono noturno e fadiga diurna. Com base no registro de polissonografia de noite inteira, qual o diagnóstico mais provável?", options: ["Síndrome da apneia/hipopneia obstrutiva do sono.", "Apneia do sono central.", "Síndrome de hipoventilação relacionada ao sono.", "O registro encontra-se dentro da normalidade, e diagnósticos alternativos devem ser buscados para explicar as queixas do paciente."], correctIndex: 2 },
  { id: "hcpa_2023_080", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Paciente masculino, de 27 anos, veio à consulta com lombalgia iniciada há 3 dias, sem melhora com paracetamol. Reflexos, força e sensibilidade preservados, dor à palpação paravertebral bilateral em região lombar, sem dor à palpação de processos espinhosos. Sinal de Lasègue negativo bilateralmente. Qual a conduta mais adequada?", options: ["Indicar repouso absoluto.", "Aumentar a dose de paracetamol.", "Prescrever anti-inflamatório não esteroidal.", "Realizar infiltração para-espinhal."], correctIndex: 2 },
  { id: "hcpa_2023_081", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A figura apresenta resultados de duas pesquisas clínicas: estudo A e estudo B, avaliando a eficácia de um mesmo tratamento hipotético sobre o desfecho morte por covid-19. A linha pontilhada significa a estimativa-ponto, e a linha contínua, a nulidade. Com base na figura, é possível afirmar que", options: ["o estudo A evidenciou que o tratamento pode piorar o desfecho principal.", "o estudo B descartou benefício do tratamento.", "o estudo B provavelmente tem menor tamanho amostral do que o estudo A.", "os estudos têm resultados divergentes."], correctIndex: 2 },
  { id: "hcpa_2023_082", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Assinale a assertiva correta sobre delineamentos de pesquisas epidemiológicas.", options: ["Os estudos observacionais descritivos testam uma hipótese, além de descreverem a distribuição de variáveis.", "Os estudos ecológicos têm como principal desvantagem o custo, pois avaliam populações inteiras, o que, muitas vezes, torna inviável sua execução.", "Os estudos de caso-controle partem dos desfechos e buscam fatores de exposição, sendo fundamental que controles venham de uma população distinta da dos casos.", "Os estudos de coorte permitem o cálculo de taxas de incidência em expostos e não expostos e, consequentemente, do Risco Relativo da doença (RR)."], correctIndex: 3 },
  { id: "hcpa_2023_083", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Para determinar os fatores de risco para o câncer de mama, 50.000 mulheres foram selecionadas e acompanhadas ao longo de 5 anos com o intuito de identificar as que desenvolveriam a doença. Qual o delineamento desse estudo?", options: ["Estudo de coorte", "Estudo de caso-controle", "Estudo transversal", "Estudo ecológico"], correctIndex: 0 },
  { id: "hcpa_2023_084", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A avaliação crítica dos resultados de publicações médicas é fortemente recomendada na formação do médico, principalmente quanto ao uso de novas tecnologias cujo nível de evidência científica é baixo. Assinale a assertiva correta sobre a análise da intenção de tratar utilizada em estudos clínicos.", options: ["É preferível à análise por protocolo em estudos observacionais.", "Preserva a randomização original dos ensaios clínicos.", "Aumenta a chance de erro tipo I.", "Reduz o tamanho da amostra."], correctIndex: 1 },
  { id: "hcpa_2023_085", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Supondo-se que o risco de morrer por pneumonia não tratada seja de 18% e que o risco de morrer por pneumonia tratada com antibióticos seja de 2%, que número de pacientes será necessário tratar com antibióticos para beneficiar um paciente no cenário descrito?", options: ["5,55", "6,25", "55", "625"], correctIndex: 2 },
  { id: "hcpa_2023_086", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo ecológico avaliou o impacto do crescimento do Programa Saúde da Família e a redução da mortalidade infantil no Brasil, de 1990 a 2002. Assinale a assertiva correta de acordo com os resultados apresentados na tabela (efeito marginal do PSF na mortalidade infantil: -4,56% para cada 10% de aumento na cobertura).", options: ["Um aumento de 10% da cobertura do Programa Saúde da Família nos municípios diminuiu em 4,56% a mortalidade infantil no período.", "O acesso à água tem efeito maior na redução da mortalidade infantil do que a cobertura do Programa Saúde da Família.", "Os leitos hospitalares têm maior impacto na redução da mortalidade infantil do que a cobertura do Programa Saúde da Família.", "O analfabetismo materno não tem impacto na mortalidade infantil."], correctIndex: 0 },
  { id: "hcpa_2023_087", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O aumento da prevalência das doenças crônicas não transmissíveis (DCNT) fez com que a ONU incluísse compromissos com a saúde e metas de controle das DCNT em sua Agenda 2030. Que alternativa melhor representa o estado atual da resposta brasileira à política de enfrentamento dessa situação de saúde?", options: ["O Brasil respondeu às recomendações da OMS para o controle do tabagismo, porém não alcançou a meta de redução da prevalência do tabagismo entre 2010 e 2019.", "O consumo de bebida alcoólica tem se reduzido no Brasil, e o decréscimo deve-se ao menor consumo de álcool pelas mulheres.", "Houve aumento na prática da atividade física no tempo livre pelos brasileiros, principal motivo para a contenção do aumento da prevalência da obesidade em adultos no país.", "A mortalidade por doenças cardiovasculares e por doenças respiratórias crônicas declinaram no Brasil entre 2010 e 2019."], correctIndex: 3 },
  { id: "hcpa_2023_088", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Conforme a Constituição Federal de 1988, a Seguridade Social compreende um conjunto integrado de ações destinadas a assegurar os direitos relativos a saúde, .......... . Segundo a Lei no 8.080/1990, não constituem despesas com ações e serviços de saúde ...........", options: ["a previdência e a assistência social – o pagamento de aposentadorias e pensões e o saneamento básico", "a previdência e a segurança pública – o pagamento de aposentadorias e pensões e o atendimento público para mulheres e vítimas de violência doméstica", "a previdência e a educação – o atendimento público para mulheres e vítimas de violência doméstica e a assistência domiciliar", "a assistência social e a educação – a merenda escolar e o saneamento básico"], correctIndex: 0 },
  { id: "hcpa_2023_089", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Associe os atributos de Atenção Primária à Saúde (Primeiro contato/acesso, Coordenação do cuidado, Longitudinalidade, Integralidade, Continuidade) às medidas de melhoria da qualidade do serviço (prontuário eletrônico; pronto-atendimento, vacinação e orientação nutricional na UBS; turno estendido até 22h). A sequência numérica correta é", options: ["1 – 2 – 3", "2 – 4 – 1", "2 – 5 – 3", "5 – 3 – 4"], correctIndex: 1 },
  { id: "hcpa_2023_090", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "A crise contemporânea dos sistemas de atenção à saúde reflete o desencontro entre envelhecimento populacional/transição epidemiológica e um sistema voltado para condições agudas, de forma fragmentada. Assinale a alternativa que aponta uma direção para superação desse problema.", options: ["A população adscrita a cada unidade de saúde é uma limitação para o exercício da atenção à saúde baseada na população, pois as pessoas devem ter liberdade de escolha", "A estrutura operacional das Redes de Atenção à Saúde pressupõe que o centro de comunicação da rede é a atenção hospitalar.", "Os sistemas logísticos, incluindo os registros eletrônicos de prontuário, não fazem parte da estrutura operacional das Redes de Atenção à Saúde, devido às limitações impostas pela LGPD.", "O Modelo de Atenção Crônica (Chronic Care Model) implica reorganização dos serviços de Atenção Primária de forma articulada com os recursos da comunidade."], correctIndex: 3 },
  { id: "hcpa_2023_091", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "As Redes de Atenção à Saúde (RAS) constituem-se em arranjos organizativos. Associe as situações clínicas (teste positivo covid-19 leve; alta pós revascularização; dor torácica na UBS; medicação parenteral após alta) às formas de cuidado (SAMU; NASF/APS; PAD; teleatendimento APS). A sequência numérica correta é", options: ["1 – 2 – 4 – 3", "1 – 4 – 2 – 3", "3 – 2 – 4 – 1", "3 – 4 – 2 – 1"], correctIndex: 2 },
  { id: "hcpa_2023_092", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Paciente feminina, de 52 anos, veio à consulta de rotina. Sem queixas, pouca atividade física, sem tabagismo. História familiar de cardiopatia isquêmica e neoplasia de pulmão. Medo de câncer, gostaria de exames pulmonares. PA aferida, coleta de Papanicolaou, exames complementares solicitados, orientada a não realizar TC de tórax por falta de evidência. Associe os níveis de prevenção (Primordial, Primária, Secundária, Terciária, Quaternária) às condutas (aferir PA; solicitar mamografia; não solicitar TC de tórax). A sequência numérica correta é", options: ["1 – 2 – 5", "2 – 3 – 4", "3 – 3 – 5", "4 – 4 – 2"], correctIndex: 2 },
  { id: "hcpa_2023_093", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Associe os casos clínicos às estratégias utilizadas por clínicos na Atenção Primária: gastroenterite com reidratação e revisão se necessário; afonia sem sintomas com retorno em 1 semana; tosse produtiva com emagrecimento e sudorese com investigação de BAAR; dor lombar bilateral em madeireiro com RX de coluna. Categorias: Espera permitida, Diagnóstico etiológico, Procedimento evitável, Diagnóstico sindrômico. A sequência numérica correta é", options: ["1 – 4 – 2 – 3", "2 – 3 – 4 – 1", "2 – 4 – 3 – 1", "3 – 1 – 4 – 2"], correctIndex: 1 },
  { id: "hcpa_2023_094", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Assinale a assertiva correta sobre normas gerais de prescrição de receitas.", options: ["Os antibióticos, incluindo os de uso tópico, são prescritos em receita comum dupla, com validade de 30 dias.", "Os analgésicos opioides e seus antagonistas devem ser prescritos em receitas B1 (azul), com numeração fornecida pela autoridade sanitária.", "Os anticonvulsivantes, os antidepressivos e os anorexígenos são prescritos em receitas de controle especial (branca, em duas vias).", "As substâncias anfetamínicas são prescritas em receitas amarelas, em talonário impresso pela autoridade sanitária."], correctIndex: 0 },
  { id: "hcpa_2023_095", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Paciente masculino, de 42 anos, consultou na UBS para obtenção de atestado médico. Fora atendido na UPA por pneumonia bacteriana há 2 dias. Trouxe RX e laudo do atendimento. Relatou melhora em relação ao dia da consulta na UPA. O médico da UPA recomendou repouso e forneceu boletim de atendimento, explicando que o atestado será fornecido pela UBS. Assinale a assertiva correta sobre o caso.", options: ["O boletim de atendimento da UPA, devidamente assinado e com a indicação da CID, é documento legal e pode ser utilizado pelo paciente como atestado médico.", "O médico da UPA tem restrição legal para fornecer atestado médico, pois não é o médico responsável pelo paciente.", "O médico da UBS deve fornecer o atestado com a data em que o atendimento foi prestado na UPA, com a indicação da CID e com o período de afastamento.", "O médico da UBS deve fornecer o atestado com a data em que o atendimento foi prestado, registrando o período completo de afastamento."], correctIndex: 3 },
  { id: "hcpa_2023_096", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Paciente feminina, de 64 anos, com transtorno de humor bipolar de longa data, veio à consulta com movimentos coreiformes e distônicos, envolvendo principalmente a face e a língua. Uso de olanzapina (10 mg/dia). Diante do diagnóstico de discinesia tardia, assinale a assertiva correta.", options: ["É mais comum ocorrer em homens jovens.", "A grande maioria dos casos melhora após 3 meses da interrupção do fármaco potencialmente implicado.", "A suspensão abrupta do fármaco potencialmente implicado deve ser evitada pelo risco de piora dos sintomas.", "Levodopa é a principal abordagem terapêutica."], correctIndex: 2 },
  { id: "hcpa_2023_097", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Paciente de 38 anos, técnica de laboratório, consultou por dor no punho e na mão direitos de início há 6 meses, evoluindo para o membro superior e ombro, incapacitante. Uso de analgésicos, AINEs, relaxantes musculares e corticosteroides, com benefício transitório. Mobilidade cervical preservada apesar da dor, sem sinais de artrite. Pontos de gatilho na região cervical e escapular. Sobre o caso, assinale a assertiva correta.", options: ["Acupuntura, agulhamento a seco e infiltração de anestésico local estão indicados.", "O uso de antidepressivos associado ao de relaxantes musculares de ação central apresenta benefício por sua ação sinérgica.", "O uso de analgésicos não opioides não apresenta benefício na dor intensa e agrega efeitos colaterais.", "Tomografia computadorizada da região cervical pode indicar a causa da dor."], correctIndex: 0 },
  { id: "hcpa_2023_098", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Urgência e Emergência", text: "Paciente de 23 anos consultou na UBS por dor escrotal muito intensa de início há 2 dias, dificuldade para deambular, disúria e mal-estar. Grande edema unilateral na bolsa escrotal. Alívio parcial da dor com a manobra de Prehn (elevação mecânica da bolsa escrotal). Qual a principal suspeita diagnóstica?", options: ["Orquiepididimite", "Hérnia inguinoescrotal encarcerada", "Torção testicular", "Hematocele"], correctIndex: 0 },
  { id: "hcpa_2023_099", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Paciente de 27 anos, casado, veio à consulta com corrimento uretral purulento e desconforto uretral há 1 semana. Não usa preservativo. Com base no quadro, assinale a assertiva correta.", options: ["Os dois principais agentes etiológicos são Trichomonas vaginalis e Chlamydia trachomatis.", "Não havendo disponibilidade laboratorial para microscopia e cultura, deve-se tratar o paciente empiricamente para clamídia e gonorreia.", "Se o corrimento uretral não for confirmado ao exame físico, o paciente deve ser reavaliado em 48 horas antes de iniciar o tratamento.", "As parcerias devem ser tratadas sempre que os sintomas persistirem após 7 dias da instituição do tratamento."], correctIndex: 1 },
  { id: "hcpa_2023_100", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Criança de 5 anos foi trazida à Emergência por laceração de 10 cm no antebraço direito, com resíduos de terra, fruto de uma queda do escorregador na praça. Os pais concordaram com a limpeza e sutura, porém recusaram, com veemência, a vacina antitetânica prescrita, por serem naturalistas contrários a vacinas há 2 anos. Diante dessa situação, o médico deve", options: ["liberar a criança e os pais, respeitando a decisão da família.", "liberar a criança e os pais e fazer um boletim de ocorrência na Delegacia de Polícia mais próxima.", "liberar a criança e os pais e fazer uma notificação para o Conselho Tutelar do domicílio da família.", "deixar a criança em observação por algumas horas para verificar eventual ocorrência de complicações."], correctIndex: 2 },
];
